<?php
namespace App\Http\Controllers;use App\Domain\Hunts\Exceptions\InvalidHuntingZoneException;use App\Domain\Hunts\Exceptions\NoEligibleMonsterException;use App\Domain\Hunts\HuntService;use App\Models\Character;use App\Models\Zone;
class CharacterHuntController extends Controller {public function index(Character $character,HuntService $s){$this->authorize('view',$character);return view('characters.hunts.index',['character'=>$character,'hunts'=>$s->history($character)]);}public function show(Character $character,$hunt,HuntService $s){$this->authorize('view',$character);return view('characters.hunts.show',['character'=>$character,'hunt'=>$s->detail($character,$hunt)]);}public function store(Character $character,Zone $zone,HuntService $s){$this->authorize('view',$character);try{$hunt=$s->start($character,$zone);return redirect()->route('characters.hunts.show',[$character,$hunt->huntId()]);}catch(InvalidHuntingZoneException $e){return redirect()->route('zones.show',$zone)->withErrors(['hunt'=>$e->getMessage()]);}catch(NoEligibleMonsterException $e){return redirect()->route('zones.show',$zone)->withErrors(['hunt'=>$e->getMessage()]);}}}
